mapper.select:
select fh.*, fc.name as carrierName, u.username as creatorName,
       date_format(fh.bill_time, '%Y-%m-%d') as billTimeStr
from jsh_freight_head fh
left join jsh_freight_carrier fc on fh.carrier_id = fc.id
left join jsh_user u on fh.creator = u.id
where fh.delete_flag = '0' and fh.tenant_id = #{tenantId}


    and fh.bill_no like #{bindBillNo}


    and fh.carrier_id = #{carrierId}


    and fh.status = #{status}


    and fh.bill_time >= #{beginTime}


    and fh.bill_time <= #{endTime}

order by fh.id desc

mapper.update:
update jsh_freight_head
set delete_flag = '1'
where delete_flag = '0'
and id in (

    #{id}

)

mapper.select:
select fc.id as carrierId, fc.name as carrierName, count(fh.id) as billCount, IFNULL(sum(fh.total_weight), 0) as totalWeight, IFNULL(sum(fh.total_freight), 0) as totalFreight, IFNULL(sum(fh.paid_amount), 0) as paidAmount, IFNULL(sum(fh.total_freight), 0) - IFNULL(sum(fh.paid_amount), 0) as unpaidAmount from jsh_freight_head fh left join jsh_freight_carrier fc on fh.carrier_id = fc.id where fh.delete_flag = '0' and fh.status = '1' and fh.tenant_id = #{tenantId}
and fh.carrier_id = #{carrierId}
and fh.bill_time >= #{beginTime}
and fh.bill_time <= #{endTime}
group by fc.id, fc.name order by totalFreight desc

select fh.id, fh.bill_no as billNo, date_format(fh.bill_time, '%Y-%m-%d') as billTimeStr, fc.name as carrierName, fh.total_weight as totalWeight, fh.unit_price as unitPrice, fh.total_freight as totalFreight, ifnull(fh.payment_status, '0') as paymentStatus, ifnull(fh.paid_amount, 0) as paidAmount, date_format(fh.payment_time, '%Y-%m-%d %H:%i') as paymentTimeStr, u2.username as paymentOperatorName, fh.remark from jsh_freight_head fh left join jsh_freight_carrier fc on fh.carrier_id = fc.id left join jsh_user u2 on fh.payment_operator = u2.id where fh.delete_flag = '0' and fh.status = '1' and fh.tenant_id = #{tenantId}
and fh.carrier_id = #{carrierId}
and fh.bill_time >= #{beginTime}
and fh.bill_time <= #{endTime}
and ifnull(fh.payment_status, '0') = #{paymentStatus}
order by fh.bill_time desc

mapper.update:
update jsh_freight_head
set status = #{status}
where delete_flag = '0'
and id in (

    #{id}

)
